import React, { useState, useEffect, useContext } from 'react';
import api from '../utils/api';
import { AuthContext } from '../context/AuthContext';
import { Link } from 'react-router-dom';
import './Dashboard.css';

const EmployerDashboard = () => {
  const { user } = useContext(AuthContext);
  const [stats, setStats] = useState(null);
  const [recentJobs, setRecentJobs] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchDashboardData = async () => {
      try {
        const response = await api.get('/employers/dashboard');
        setStats(response.data.stats);
        setRecentJobs(response.data.recentJobs);
      } catch (error) {
        console.error('Error fetching dashboard data:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchDashboardData();
  }, []);

  if (loading) return <div className="loading">Loading dashboard...</div>;

  return (
    <div className="dashboard-container">
      <header className="dashboard-header">
        <div className="header-top">
          <h1>Employer Dashboard</h1>
          <Link to="/post-job" className="post-job-btn">Post a New Job</Link>
        </div>
        <div className="stats-grid">
          <div className="stat-card">
            <h3>Jobs Posted</h3>
            <p className="stat-value">{stats?.totalJobsPosted || 0}</p>
          </div>
          <div className="stat-card">
            <h3>Active Jobs</h3>
            <p className="stat-value">{stats?.activeJobs || 0}</p>
          </div>
          <div className="stat-card">
            <h3>Total Spent</h3>
            <p className="stat-value">₹{stats?.totalSpent || 0}</p>
          </div>
          <div className="stat-card">
            <h3>Pending Applications</h3>
            <p className="stat-value">{stats?.pendingApplications || 0}</p>
          </div>
        </div>
      </header>

      <section className="dashboard-content">
        <div className="content-header">
          <h2>Your Recent Postings</h2>
        </div>
        
        <div className="jobs-list">
          {recentJobs.length > 0 ? (
            recentJobs.map(job => (
              <div key={job._id} className="job-card">
                <div className="job-info">
                  <h3>{job.title}</h3>
                  <p className={`status-badge ${job.status}`}>{job.status}</p>
                  <p className="job-meta">Posted on {new Date(job.createdAt).toLocaleDateString()}</p>
                </div>
                <div className="job-action">
                  <p className="app-count">{job.applications?.length || 0} Applications</p>
                  <Link to={`/job/${job._id}`} className="view-btn">Manage Job</Link>
                </div>
              </div>
            ))
          ) : (
            <p className="no-data">You haven't posted any jobs yet.</p>
          )}
        </div>
      </section>
    </div>
  );
};

export default EmployerDashboard;
